mapper.select:
SELECT DISTINCT s.id, s.title, s.description, s.owner_id, s.start_time, s.end_time, s.location, s.is_all_day, s.visibility, s.color, s.created_at, s.updated_at, u.name AS owner_name FROM gw_schedules s JOIN itsm_users u ON s.owner_id = u.id LEFT JOIN gw_schedule_attendees sa ON sa.schedule_id = s.id WHERE (s.owner_id = #{userId} OR sa.user_id = #{userId})
AND s.end_time >= #{start}
AND s.start_time <= #{end}
ORDER BY s.start_time ASC

SELECT DISTINCT s.id, s.title, s.description, s.owner_id, s.start_time, s.end_time, s.location, s.is_all_day, s.visibility, s.color, s.created_at, s.updated_at, u.name AS owner_name FROM gw_schedules s JOIN itsm_users u ON s.owner_id = u.id JOIN gw_user_profiles up ON u.id = up.user_id JOIN gw_user_profiles myProfile ON myProfile.user_id = #{userId} WHERE s.visibility IN ('PUBLIC', 'TEAM') AND up.department_id = myProfile.department_id
AND s.end_time >= #{start}
AND s.start_time <= #{end}
ORDER BY s.start_time ASC

SELECT id, name, capacity, location, description, created_at
FROM gw_meeting_rooms
WHERE id = #{id}

SELECT rb.id, rb.room_id, rb.schedule_id, rb.booked_by, rb.start_time, rb.end_time, rb.purpose, rb.created_at, u.name AS booked_by_name, mr.name AS room_name FROM gw_room_bookings rb JOIN itsm_users u ON rb.booked_by = u.id JOIN gw_meeting_rooms mr ON rb.room_id = mr.id WHERE rb.room_id = #{roomId}
AND rb.end_time >= #{start}
AND rb.start_time <= #{end}
ORDER BY rb.start_time ASC

SELECT EXISTS(
    SELECT 1 FROM gw_room_bookings
    WHERE room_id = #{roomId}
      AND start_time < #{endTime}
      AND end_time > #{startTime}

          AND id != #{excludeId}

)
